HRESULT WinBioAsyncEnumBiometricUnits(
[in] WINBIO_FRAMEWORK_HANDLE FrameworkHandle,
[in] WINBIO_BIOMETRIC_TYPE   Factor);

HRESULT WinBioAsyncMonitorFrameworkChanges(
[in] WINBIO_FRAMEWORK_HANDLE      FrameworkHandle,
[in] WINBIO_FRAMEWORK_CHANGE_TYPE ChangeTypes);

HRESULT WinBioEnumServiceProviders(   [in]  WINBIO_BIOMETRIC_TYPE Factor,
[out] WINBIO_BSP_SCHEMA     **BspSchemaArray,
[out] SIZE_T                *BspCount);

HRESULT WinBioReleaseFocus();

### Return value
If the function succeeds, it returns S_OK. If it fails, it returns an HRESULT error code.

HRESULT WinBioRemoveCredential(
[in] WINBIO_IDENTITY        Identity,
[in] WINBIO_CREDENTIAL_TYPE Type);

typedef struct _WINBIO_ASYNC_RESULT {   WINBIO_SESSION_HANDLE SessionHandle;   WINBIO_OPERATION_TYPE Operation;
ULONGLONG             SequenceNumber;
LONGLONG              TimeStamp;   HRESULT               ApiStatus;

typedef struct _WINBIO_PIPELINE {
    HANDLE SensorHandle;
    HANDLE EngineHandle;
    HANDLE StorageHandle;
    PVOID SensorContext;
    PWINBIO_SENSOR_INTERFACE SensorInterface;
    PWINBIO_ENGINE_INTERFACE EngineInterface;
    PWINBIO_STORAGE_INTERFACE StorageInterface;
} WINBIO_PIPELINE;

HRESULT WinBioEnrollCaptureWithCallback(
[in]           WINBIO_SESSION_HANDLE           SessionHandle,   [in]           PWINBIO_ENROLL_CAPTURE_CALLBACK EnrollCallback,
[in, optional] PVOID                           EnrollCallbackContext);

HRESULT WinBioEnrollBegin(
[in] WINBIO_SESSION_HANDLE    SessionHandle,   [in] WINBIO_BIOMETRIC_SUBTYPE SubFactor,
[in] WINBIO_UNIT_ID           UnitId);

HRESULT WinBioAsyncEnumDatabases(
[in] WINBIO_FRAMEWORK_HANDLE FrameworkHandle,
[in] WINBIO_BIOMETRIC_TYPE   Factor);

HRESULT WinBioAsyncEnumServiceProviders(
[in] WINBIO_FRAMEWORK_HANDLE FrameworkHandle,
[in] WINBIO_BIOMETRIC_TYPE   Factor);

HRESULT WinBioDeleteTemplate(
[in] WINBIO_SESSION_HANDLE    SessionHandle,   [in] WINBIO_UNIT_ID           UnitId,
[in] WINBIO_IDENTITY          *Identity,   [in] WINBIO_BIOMETRIC_SUBTYPE SubFactor);

HRESULT WinBioUnlockUnit(
[in] WINBIO_SESSION_HANDLE SessionHandle,
[in] WINBIO_UNIT_ID        UnitId);

HRESULT WinBioGetCredentialState(
[in]  WINBIO_IDENTITY         Identity,   [in]  WINBIO_CREDENTIAL_TYPE  Type,
[out] WINBIO_CREDENTIAL_STATE *CredentialState);

HRESULT WinBioLocateSensorWithCallback(
[in]           WINBIO_SESSION_HANDLE          SessionHandle,   [in]           PWINBIO_LOCATE_SENSOR_CALLBACK LocateCallback,
[in, optional] PVOID                          LocateCallbackContext);

HRESULT WinBioLockUnit(
[in] WINBIO_SESSION_HANDLE SessionHandle,
[in] WINBIO_UNIT_ID        UnitId);

HRESULT WinBioRegisterEventMonitor(
  [in] WINBIO_SESSION_HANDLE SessionHandle,
  [in] WINBIO_EVENT_MASK EventMask,
  [in] PWINBIO_EVENT_CALLBACK EventCallback,
  [in, optional] PVOID UserData
);

typedef struct _WINBIO_ADAPTER_INTERFACE_VERSION {
USHORT MajorVersion;   USHORT MinorVersion;
} WINBIO_ADAPTER_INTERFACE_VERSION, *PWINBIO_ADAPTER_INTERFACE_VERSION;
